import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"然山内功","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/太吾绘卷/然山内功.md","filePath":"4.资源分区/6.技艺及称号/武技类/太吾绘卷/然山内功.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/太吾绘卷/然山内功.md"};function p(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"然山内功",tabindex:"-1"},[n("然山内功 "),r("a",{class:"header-anchor",href:"#然山内功","aria-label":'Permalink to "然山内功"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),s('<h1 id="然山派内功" tabindex="-1">然山派内功 <a class="header-anchor" href="#然山派内功" aria-label="Permalink to &quot;然山派内功&quot;">​</a></h1><p>然山内功<br> 以下所有内功在购买之后，还必须遵守“运功位”的限制。你每具有2点武学掌握专业就具有一个“运功位”。只有合法地占据了“运功位”的内功才能生效。（如果其他资源也注明了对于运功上限的需要，那么不同资源之间的运功上限不是单独的，而是共享的。）一般来说，越是强大的内功占据的运功上限就越多。<br> 正练与逆练：正练与逆练的效果需要在兑换下述内功的时候选择一个获得。一经选择，不得更改或者选择另一个（除非有特殊标注）。</p><p>【养志法】<br> 价格：D+500<br> 描述：“有所欲，志存而思之。志者，欲之使也”。养志法乃是存志使欲，凝心固气，使人神志清明、思理通达的内家心法。<br> 这是一个【紫霞】属性的内功。<br> 这个内功如果要生效，需要占据1个“运功位”。只要该内功在一整部影片内始终占据着所需的“运功位”，那么在影片结束时，你就会获得2点仅能用于提升决心和沉着属性或耐力和感知属性的xp，或者你也可以放弃获得这两点xp，改为获得1点意志池的上限。这个效果最多获得3次。<br> 正练效果：你使用的然山派的可以进行攻击的招式，在攻击时额外获得1点附加成功。<br> 逆练效果：你使用的然山派的可以进行攻击的招式，在使用时会减少1点内力的消耗，在这个内功占据“运功位”期间，你生理属性的检定上获得1点能量加值。</p><p>【转圆法】<br> 价格：D+1000<br> 描述：转圆法用圆求合，与造化为始，转化接物，以观进退，以不测之智求混沌之道，故能有无穷之计。<br> 这是一个【混元】属性的内功。<br> 这个内功如果要生效，需要占据1个“运功位”。只要该内功占据着所需的“运功位”，那么你的意志豁免会获得等同于内力能量池等级*2的能量加值。<br> 正练效果：你在攻击时，具有1点环境加值。你每具有1点社交技能上的附加成功，这个加值提升1点。<br> 逆练效果：你在攻击时，具有1点环境加值。你每具有1点专注技能上的附加成功，这个加值提升1点。</p><p>【实意法】<br> 价格：C+1000<br> 描述：实意法讲究静心远虑，无为而求，精神固守，内视反听，修习者思之太虚，待神往来，可使五脏和通，可知阴阳造化。<br> 这是一个【紫霞】属性的内功。<br> 这个内功如果要生效，需要占据1个“运功位”。只要该内功在一整部影片内始终占据着所需的“运功位”，那么在影片结束时，你就会获得1点意志力用法加值的提升，并且扩大1点意志力池，这个效果最多获得2次。。<br> 正练效果：只要你还有别的【紫霞】属性的内功占据了运功位，那么你在应对攻击时，如果使用了意志力的基础用法，那么还会额外获得2点抵威猛，并且防御上额外获得1点附加成功。<br> 逆练效果：只要你还有别的【紫霞】属性的内功占据了运功位，那么你在应对攻击时，如果使用了意志力的基础用法，那么还会额外获得2点抵破甲，并且防御上额外获得1点附加成功。</p><p>【损悦法】<br> 价格：C+2000<br> 描述：“悦者，知之也。损者，行之也”。损悦法效仿圣人，以无为待有德，观事之适然、物之成败，以为机危之决，故能使人辞不烦而心不虚，志不乱而意不邪。<br> 这是一个【混元】属性的内功。<br> 这个内功如果要生效，需要占据1个“运功位”。只要该内功在一整部影片内始终占据着所需的“运功位”，那么在完整运功这个内功的第一个影片结束时，你就会获得B级别的针对影响心灵效果的免疫。第二个影片结束时，你还会获得1点异常点数治疗（医疗点24）。<br> 正练效果：你运功这个内功时，在防御上额外具有传奇智力*2+1点洞察防御。<br> 逆练效果：你运功这个内功时，在攻击时，如果为攻击应用了传奇智力的用法，那么这次传奇智力一场景一次的用法所能够变为成功的骰子个数+3个。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
